// GET /api/admin/book-loans
exports.getAll = async (req, res, next) => {
  try {
    const { page = 1, limit = 20, search, status } = req.query;
    const offset = (page - 1) * limit;

    let query = `SELECT * FROM book_loans WHERE 1=1`;
    const params = [];
    let paramIndex = 1;

    if (search) {
      query += ` AND (slug ILIKE $${paramIndex} OR name::text ILIKE $${paramIndex})`;
      params.push(`%${search}%`);
      paramIndex++;
    }

    if (status && status !== 'undefined') {
      query += ` AND status = $${paramIndex}`;
      params.push(status);
      paramIndex++;
    }

    query += ` ORDER BY created_at DESC LIMIT $${paramIndex} OFFSET $${paramIndex + 1}`;
    params.push(parseInt(limit), offset);

    const { rows } = await pool.query(query, params);

    // Get total count with same filters
    let countQuery = 'SELECT COUNT(*) as total FROM book_loans WHERE 1=1';
    const countParams = [];
    let countParamIndex = 1;

    if (search) {
      countQuery += ` AND (slug ILIKE $${countParamIndex} OR name::text ILIKE $${countParamIndex})`;
      countParams.push(`%${search}%`);
      countParamIndex++;
    }

    if (status && status !== 'undefined') {
      countQuery += ` AND status = $${countParamIndex}`;
      countParams.push(status);
      countParamIndex++;
    }

    const { rows: countRows } = await pool.query(countQuery, countParams);

    return res.json({
      success: true,
      data: rows,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: parseInt(countRows[0].total),
        totalPages: Math.ceil(countRows[0].total / limit),
      },
    });
  } catch (error) {
    return next(error);
  }
};

// GET /api/admin/book-loans/:id
exports.getById = async (req, res, next) => {
  try {
    const { id } = req.params;
    const query = `
      SELECT bl.*, 
             m.full_name as member_name, m.card_number as member_card, m.email as member_email, m.phone as member_phone,
             b.title->>'vi' as book_title, b.author as book_author, b.cover_image, b.media_type, b.access_policy,
             c.barcode as copy_barcode, c.condition as copy_condition
      FROM book_loans bl
      JOIN members m ON bl.member_id = m.id
      JOIN books b ON bl.book_id = b.id
      LEFT JOIN publication_copies c ON bl.copy_id = c.id
      WHERE bl.id = $1
    `;
    const { rows } = await pool.query(query, [id]);

    if (rows.length === 0) {
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy phiếu mượn',
      });
    }

    return res.json({
      success: true,
      data: rows[0],
    });
  } catch (error) {
    return next(error);
  }
};

// POST /api/admin/book-loans
exports.create = async (req, res, next) => {
  const client = await pool.connect();
  try {
    const data = req.body;
    const { member_id } = data;

    if (!member_id) {
      return res.status(400).json({ success: false, message: 'Thiếu ID hội viên' });
    }

    await client.query('BEGIN');

    // 1. Kiểm tra trạng thái thẻ & Hạn mức thực tế (Đồng bộ hóa Expiry)
    const { rows: members } = await client.query(`
      SELECT m.*, mp.max_books_borrowed, mp.tier_code, mp.name->>'vi' as plan_name
      FROM members m
      LEFT JOIN membership_plans mp ON m.membership_plan_id = mp.id
      WHERE m.id = $1
    `, [member_id]);

    if (members.length === 0) {
      throw new Error('Hội viên không tồn tại');
    }

    const member = members[0];
    if (member.status !== 'active') {
      throw new Error(`Thẻ này đang ở trạng thái "${member.status}", không thể mượn sách.`);
    }

    const effective = getEffectiveMembership({
      membership_expires: member.membership_expires,
      tier_code: member.tier_code || 'basic',
      plan_name: member.plan_name || 'Cơ bản',
      max_books_borrowed: member.max_books_borrowed || 3
    });

    // 2. Kiểm tra số sách đang mượn
    const { rows: currentLoans } = await client.query(`
      SELECT COUNT(*) as count 
      FROM book_loans 
      WHERE member_id = $1 AND status IN ('borrowing', 'overdue')
    `, [member_id]);

    const activeCount = parseInt(currentLoans[0].count);

    if (activeCount >= effective.max_books_borrowed) {
      throw new Error(`Hội viên đã đạt giới hạn mượn sách (${effective.max_books_borrowed} cuốn). Vui lòng trả sách hoặc nâng cấp thẻ để mượn tiếp.`);
    }

    // 3. Thực hiện tạo phiếu mượn
    const fields = Object.keys(data).join(', ');
    const values = Object.keys(data).map((_, i) => `$${i + 1}`).join(', ');
    const params = Object.values(data);

    const { rows } = await client.query(
      `INSERT INTO book_loans (${fields}) VALUES (${values}) RETURNING *`,
      params
    );

    await client.query('COMMIT');

    return res.status(201).json({
      success: true,
      message: 'Đã tạo bookloan thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

// PUT /api/admin/book-loans/:id
exports.update = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { id } = req.params;
    const data = req.body;

    // Check if exists
    const { rows: existing } = await client.query('SELECT * FROM book_loans WHERE id = $1', [id]);
    if (existing.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy bookloan',
      });
    }

    // Build update query
    const updateFields = [];
    const params = [];
    let paramIndex = 1;

    Object.keys(data).forEach(key => {
      if (data[key] !== undefined) {
        updateFields.push(`${key} = $${paramIndex++}`);
        params.push(data[key]);
      }
    });

    if (updateFields.length > 0) {
      params.push(id);
      await client.query(
        `UPDATE book_loans SET ${updateFields.join(', ')} WHERE id = $${paramIndex}`,
        params
      );
    }

    await client.query('COMMIT');

    const { rows } = await client.query('SELECT * FROM book_loans WHERE id = $1', [id]);

    return res.json({
      success: true,
      message: 'Đã cập nhật bookloan thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

